"""
MKT Original Commentary — Hebrews chapters 1–5 (gap-fill pass)
Run: python3 scripts/zc-original-hebrews-1-5-gaps.py

Source data used:
- data/interlinear/hebrews.json
- data/translation/glossary-greek.json (selected terms)
- data/translation/draft/mediating/hebrews.json (MKT text)

Key decisions in this range:
- 1:6 palin: temporal/logical connective; LXX Deut 32:43 / Ps 97:7 background
- 1:9 chrio: anointing verb behind christos; Ps 45 activates royal-messianic register
- 2:4 merismos: sovereign apportionment of Spirit gifts, not human attainment
- 2:6-8 Ps 8 applied to Jesus: anthrōpos/huios anthrōpou fulfilled only in Christ
- 2:13 Isa 8:17-18: double citation links Messiah trust in God with solidarity with children
- 2:16 epilambanomai: vivid seizure verb; Son decisively grasps Abraham seed, not angels
- 3:2-5 oikos structure: servant-in-house (Moses) vs. son-over-house (Christ)
- 4:9 sabbatismos: NT hapax distinct from katapausis; eschatological Sabbath
- 5:5-6 two Ps citations: Ps 2:7 (sonship) + Ps 110:4 (Melchizedek order) as dual divine appointment
- 5:14 aisthētēria: trained perceptual organs of moral discernment; philosophical term
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = json.loads(r'''
{
  "1": {
    "6": "<p><strong>hotan de palin eisagagē ton prōtotokon eis tēn oikoumenēn</strong> — \"And again, when he brings the firstborn into the world\" (<em>palin</em>: again — the particle is ambiguous; it may connect to \"he says\" [another citation follows] or modify <em>eisagagē</em> [bringing in a second time, i.e., the second coming]; most likely it serves as a connective introducing the next citation): <em>prōtotokon</em> (firstborn — G4416: <em>prōtotokos</em>) carries the double weight of priority and privilege — in Jewish inheritance law the firstborn holds the highest claim. The \"bringing into the world\" (<em>eis tēn oikoumenēn</em>) refers either to the incarnation or the eschatological enthronement.</p><p><strong>proskynesatōsan autō pantes angeloi theou</strong> — \"Let all God's angels worship him\" (from Deut 32:43 LXX or Ps 97:7): <em>proskynesatōsan</em> (third-person aorist imperative of <em>proskyneō</em>: to worship, to bow before) — the divine command that all angels bow to the Son makes explicit what the entire catena of citations argues: the Son receives divine honor that no angel can claim or receive.</p>",
    "9": "<p><strong>ēgapēsas dikaiosynēn kai emisēsas anomian</strong> — \"You have loved righteousness and hated wickedness\" (Ps 45:7): the perfect tenses (<em>ēgapēsas</em>, <em>emisēsas</em>) describe a completed moral orientation that defines the king's character — not a momentary act but an established disposition of the will. The polarity <em>dikaiosynē</em>/<em>anomia</em> (righteousness/lawlessness) is absolute; the king has not merely preferred righteousness but actively hated its opposite.</p><p><strong>echrien se ho theos, ho theos sou, elaion agalliaseōs para tous metochous sou</strong> — \"therefore God, your God, has anointed you with the oil of gladness beyond your companions\" (<em>echrien</em>: anointed — aorist of <em>chriō</em> [G5548], the verb behind <em>christos</em>): the citation activates the messianic register of the Psalm — the one addressed as <em>ho theos</em> (v8) is also the one anointed by God (<em>ho theos sou</em>). The vocative + nominative address in vv8-9 distinguishes the addressee (the Son) and the anointer (the Father). <em>Elaion agalliaseōs</em> (oil of gladness) — the anointing oil is not cultic but celebratory, marking exaltation over all companions (<em>metochous</em>: partners/sharers — later used for Christ's \"partners\" in Heb 3:14).</p>",
    "11": "<p><strong>autoi apolountai, sy de diameneis</strong> — \"They will perish, but you remain\" (Ps 102:26 LXX): the contrast is ontological and grammatical: <em>apolountai</em> (they shall perish — future middle: their destruction is their own end) vs. <em>diameneis</em> (you remain through-and-through — <em>dia</em> intensifies the permanence). The heavens and earth are the antecedent of \"they\" — the entire created cosmos is subject to decay, while the Son endures. <em>Pantes hōs himation palaióthēsontai</em> (all of them shall grow old like a garment) — the aging metaphor: garments that once served their function become thread-worn and discardable.</p>",
    "12": "<p><strong>hōsei peribolaion helixeis autous kai allagēsontai, sy de ho autos ei kai ta etē sou ouk ekleipsousin</strong> — \"You will roll them up like a robe; like a garment they will be changed. But you are the same, and your years will never end\" (Ps 102:27 LXX): <em>peribolaion</em> (robe, wrapper — G4018: something wrapped around): the Creator rolls up the cosmos as a garment rolled up after use — the image speaks to the deliberate sovereign act of the Son at the end of the age. <em>Allagēsontai</em> (they shall be changed — future passive): the heavens and earth are subject to change, not the Son. <em>Sy de ho autos ei</em> — \"but you are the same\" (<em>ho autos</em>: the same, unchanged — applied to the Son as the citation's referent): Hebrews reads the Ps 102 <em>Kyrios</em>-address as addressed to the Son, identifying the Son's divine immutability with the LORD of the Psalm. <em>Ta etē sou ouk ekleipsousin</em> (your years will not fail/fall short): <em>ekleipsousin</em> from <em>ekleipō</em> — to fail, to be eclipsed (as in a solar eclipse); the Son's years cannot be eclipsed by any temporal end.</p>"
  },
  "2": {
    "2": "<p><strong>ei gar ho di' angelōn lalētheis logos egeneto bebaios</strong> — \"For if the message declared through angels was reliable\" (<em>bebaios</em>: firm, reliable, legally valid — a legal-commercial term for a guarantee that stands; used in papyri for a deed that conveys secure ownership): the Torah was understood in Second Temple tradition to have been mediated by angels (Deut 33:2 LXX; Gal 3:19; Acts 7:53) — its reliability (<em>bebaios</em>) is the argumentative baseline. If angel-mediated law carried penal force, how much more does Son-mediated salvation demand a response.</p><p><strong>kai pasa parabasis kai parakoē elaben endikon misthapodosian</strong> — \"and every transgression and act of disobedience received a just penalty\" (<em>parabasis</em>: transgression, stepping over a boundary [<em>para</em> + <em>bainō</em>]; <em>parakoē</em>: disobedience, failure to hear fully [<em>para</em> + <em>akouō</em>]): the two terms cover active violation of explicit command (<em>parabasis</em>) and passive failure to heed (<em>parakoē</em>). <em>Endikos misthapodosian</em> (just reward/penalty — <em>misthapodosia</em>: payment of wages due): the penalty is not arbitrary but proportional and legally due.</p>",
    "4": "<p><strong>synepimartyroutos theou sēmeiois te kai terasin kai poikilais dynamesin kai pneumatos hagiou merismoiis kata tēn autou thelēsin</strong> — \"while God confirmed their message with signs, wonders, various miracles, and gifts of the Holy Spirit distributed according to his will\" (<em>synepimartyroutos</em>: co-testifying with, bearing joint-witness — <em>syn</em> + <em>epi</em> + <em>martyreō</em>: an intensified compound; God's confirmatory witness accompanied the apostolic message): the three nouns <em>sēmeia</em> (signs), <em>terata</em> (wonders), <em>dynameis</em> (acts of power, miracles) are a stock NT formulaic sequence for the miraculous attestation of divine activity.</p><p><strong>pneumatos hagiou merismoiis kata tēn autou thelēsin</strong> — \"gifts of the Holy Spirit distributed according to his will\" (<em>merismoiis</em>: distributions, dividings-out — from <em>merizō</em>; <em>merismos</em> implies sovereign apportionment): the Spirit-gifts are not human attainments but divine distributions allocated according to God's own will (<em>kata tēn autou thelēsin</em>), not the recipient's worthiness or request.</p>",
    "5": "<p><strong>ou gar angelois hypetaxen tēn oikoumenēn tēn mellousan, peri hēs laloumen</strong> — \"For God did not subject the coming world — the world we are speaking about — to angels\" (<em>oikoumenēn tēn mellousan</em>: the coming inhabited world — <em>oikoumenē</em> is the inhabited earth/Roman world, but here in its eschatological sense, the world-to-come): the parenthetical <em>peri hēs laloumen</em> (about which we speak) identifies the topic: the coming world is the realm under discussion throughout. Angels govern the present age (understood in Second Temple cosmology); the coming age will not be theirs.</p>",
    "6": "<p><strong>diemartyrato de pou tis legōn, Ti estin anthrōpos hoti mimnēskē autou, ē huios anthrōpou hoti episkeptē auton</strong> — \"But there is a place where someone has testified: What is man that you are mindful of him, or the son of man that you care for him?\" (Ps 8:4 LXX): the indefinite attribution (<em>diemartyrato de pou tis</em>: testified somewhere someone) is a deliberate distancing device — Hebrews cites the Psalm's divine authority, not the human author's identity. <em>Ti estin anthrōpos</em> (What is man?) — the Psalm's original frame is human smallness contrasted with God's grandeur. Hebrews will read it as a question whose only adequate answer is the Son of Man who became low and was exalted. <em>Episkeptē</em> (you care for/visit — from <em>episkeptomai</em>: to look upon with care, to visit with saving intent; the word carries the covenantal visit-to-rescue connotation).</p>",
    "7": "<p><strong>ēlatōsas auton brachy ti par' angelous, doxē kai timē estephanōsas auton, kai katestēsas auton epi ta erga tōn cheirōn sou</strong> — \"You made him a little lower than the angels; you crowned him with glory and honor and set him over the works of your hands\" (Ps 8:5-6 LXX): <em>brachy ti par' angelous ēlatōsas</em> (you made lower by a little than/beside angels — <em>ēlatōsas</em>: aorist of <em>elattoō</em>, to diminish, lower; <em>brachy ti</em>: a little, for a short time): Hebrews will read the \"little\" as both degree (slightly lower in rank) and duration (for a brief time of humiliation). The LXX reads the Hebrew <em>elohim</em> as \"angels\" — Hebrews follows the LXX. <em>Estephanōsas</em> (you crowned — aorist): the crowning is the exaltation-event, historically completed.</p>",
    "8": "<p><strong>panta hypetaxas hypokatō tōn podōn autou... nyn de oupō horōmen autō ta panta hypotetagmena</strong> — \"You have put everything under his feet... yet at present we do not see everything subject to him\": <em>panta hypetaxas hypokatō tōn podōn autou</em> (Ps 8:6b LXX) — \"everything\" is the universal scope, including the angels. <em>En tō gar hypotaxai autō ta panta, ouden aphēken autō anypotakton</em> (in the subjecting of all things to him, he left nothing not subjected to him) — the grammar is deliberate: the aorist subjection (<em>hypotaxai</em>) is comprehensive in scope but the present experience does not yet match it. <em>Nyn de oupō horōmen</em> (but now not yet we see) — the \"not yet\" is eschatological, not an admission of failure; the tension between \"all things subjected\" and \"not yet visible\" is resolved in v9 by pointing to the one who already went through death and was crowned.</p>",
    "12": "<p><strong>legōn, Apaggeleō to onoma sou tois adelphois mou, en mesō ekklēsias hymnēsō se</strong> — \"saying: I will proclaim your name to my brothers and sisters; in the midst of the assembly I will sing your praise\" (Ps 22:22 LXX): the citation puts Ps 22 in the mouth of the Son — the Psalm that begins with the cry of dereliction (Ps 22:1, quoted at the cross) ends with the resolution to proclaim God's name to the community. <em>Apaggeleō</em> (I will report/announce — a strong public proclamation); <em>en mesō ekklēsias</em> (in the midst of the assembly/church — <em>ekklēsia</em>): the word the NT uses for the gathered community appears here in an OT psalm, read as the Son's own declaration of solidarity and praise.</p>",
    "13": "<p><strong>kai palin, Egō esomai pepoithōs ep' autō</strong> — \"And again, I will trust in him\" (Isa 8:17 LXX): a second OT citation placed in the Son's mouth. <em>Pepoithōs ep' autō</em> (trusting upon him — perfect participle of <em>peithō</em>: to convince; perfect = standing in a state of settled trust): the Son himself models the faith-posture to which Hebrews calls its community — trust in God even through suffering and apparent divine hiddenness, which is exactly the Isaiah 8 context (God hiding his face while the remnant trusts).</p><p><strong>kai palin, Idou egō kai ta paidia ha moi edōken ho theos</strong> — \"and again, Here am I and the children God has given me\" (Isa 8:18 LXX): <em>paidia</em> (children — G3813, a term of smallness and dependence): the Son presents \"the children\" as those entrusted to him — the same solidary language as v11 (<em>adelphous</em>) and v14 (<em>ta paidia</em>). The double Isa 8 citation establishes the Son as the Servant-remnant figure who trusts God and maintains solidarity with his people through the dark time.</p>",
    "14": "<p><strong>epei oun ta paidia kekoinōnēken haimatos kai sarkos kai autos paraplēsiōs metesche tōn autōn</strong> — \"Since the children share in flesh and blood, he himself likewise took part in these\" (<em>kekoinōnēken</em>: perfect active — they have and continue to share in flesh and blood, an established condition; <em>metesche</em>: aorist — he took part, a historical once-for-all act): the contrast of tenses is precise — the children's flesh-and-blood existence is their ongoing state; the Son's taking part is the historical incarnation event. <em>Paraplēsiōs</em> (in like manner, closely parallel — a comparative adverb expressing real resemblance, not mere analogy).</p><p><strong>hina dia tou thanatou katargēsē ton to kratos echonta tou thanatou, tout' estin ton diabolon</strong> — \"so that through death he might destroy the one who holds the power of death — that is, the devil\" (<em>katargēsē</em>: aorist subjunctive of <em>katargeō</em>: to render inoperative, to nullify, to bring to nothing — not annihilation but de-powering): the means of destruction is the weapon itself — death is used against the death-holder. <em>Ton to kratos echonta tou thanatou</em> (the one having the power/strength of death): <em>kratos</em> (G2904) is brute power/dominion — the devil's grip on death is expressed as a possession he holds, not an inherent attribute.</p>",
    "15": "<p><strong>kai apallaxē toutous, hosoi phobō thanatou dia pantos tou zēn enochoi ēsan douleias</strong> — \"and free all those who all their lives had been held in slavery by their fear of death\" (<em>apallaxē</em>: aorist subjunctive of <em>apallassō</em>: to release, set free, rid of — medical use for relieving a patient of disease): <em>phobō thanatou</em> (fear of death) — <em>phobos</em> here is the enslaving dread that structures human life under the threat of mortality. <em>Enochoi ēsan douleias</em> (were held liable to/subject to bondage): <em>enochos</em> (G1777) is a legal term — one who is bound/guilty; the slavery is legally constituted by the liability that the fear of death imposes on human existence.</p>",
    "16": "<p><strong>ou gar dēpou angelōn epilambanetai, alla spermatos Abraam epilambanetai</strong> — \"For surely it is not angels he helps, but Abraham's descendants\" (<em>epilambanetai</em>: to take hold of, to seize, to grasp — present middle; the verb is vivid: the Son decisively lays hold of Abraham's seed): <em>ou gar dēpou angelōn</em> (for surely not of angels — <em>dēpou</em> is an emphatic particle asserting what is obvious or certain): the Son's assumption of human nature was directed specifically at Abraham's seed. <em>Spermatos Abraam</em> (Abraham's seed — <em>sperma</em>): the corporate seed of Abraham, the covenant people, is the specific humanity the Son joined — not human nature in general, and not angels at all.</p>"
  },
  "3": {
    "2": "<p><strong>piston onti tō poiēsanti auton, hōs kai Mōysēs en holō tō oikō autou</strong> — \"He was faithful to the one who appointed him, just as Moses was faithful in all God's house\" (<em>pistos</em>: faithful, trustworthy — G4103): the comparison with Moses is the tertium comparationis — faithfulness. The ground-point is the same (faithfulness to the one who appointed); the contrast will be the position (v5-6: servant vs. son). <em>Tō poiēsanti auton</em> (to the one who made/appointed him — <em>poieō</em> here carries the sense of appointment/commissioning, not creation): the Son's faithfulness is to his vocational appointment, not a statement about origins.</p>",
    "3": "<p><strong>pleionos gar doxēs houtos para Mōysēn ēxiōtai, kath' hoson pleiona timēn echei tou oikou ho kataskeuasas auton</strong> — \"But Jesus has been found worthy of greater honor than Moses — just as the builder of a house deserves more honor than the house itself\" (<em>ēxiōtai</em>: perfect passive of <em>axioō</em>: to account worthy — permanently counted as worthy): the comparison is structural: builder > house in honor. Moses is part of the house; the Son built it. <em>Pleionos doxēs</em> (more glory — genitive of comparison with <em>pleionos</em>): the comparison is about degree of glory, not denial of Moses's glory; the greater/lesser structure is the rhetorical engine of Hebrews throughout.</p>",
    "4": "<p><strong>pas gar oikos kataskeuazetai hypo tinos, ho de panta kataskeuasas theos</strong> — \"Every house is built by someone, but God is the builder of everything\" (<em>kataskeuazetai hypo tinos</em>: is constructed by someone — passive, with a builder implied): the premise is universal (every house requires a builder) and leads to the inference that if the Son built the house (v3), he participates in the divine building role, since all building ultimately traces back to God. The verse grounds the Son's superiority to Moses in the Son's participation in divine creative agency.</p>",
    "5": "<p><strong>kai Mōysēs men pistos en holō tō oikō autou hōs therapōn, eis martyrion tōn lalēthēsomenōn</strong> — \"Moses was faithful as a servant in all God's house, giving testimony to what would be said in the future\" (<em>therapōn</em>: servant, attendant — G2324, a word of dignity; not the ordinary <em>doulos</em> [slave] but a personal attendant in a position of honor; used of Moses only in the LXX [Num 12:7]): the servant-position is honorable but subordinate. <em>Eis martyrion tōn lalēthēsomenōn</em> (for a testimony of the things that would be spoken): Moses's entire ministry was anticipatory — a forward-pointing witness to the realities that would be spoken in the Son.</p>",
    "7": "<p><strong>dio kathōs legei to pneuma to hagion, Sēmeron ean tēs phōnēs autou akousēte</strong> — \"So, as the Holy Spirit says: Today, if you hear his voice,\" (Ps 95:7-8 LXX): the attribution to <em>to pneuma to hagion</em> (the Holy Spirit) as the one who speaks (<em>legei</em> — present tense) makes the Psalm's address present and ongoing: the Spirit continues to speak this word to the community. <em>Sēmeron</em> (today) — the Psalm's urgent temporal marker that Hebrews will develop into the \"today\" of the community's hearing moment.</p>",
    "8": "<p><strong>mē sklērynēte tas kardias hymōn hōs en tō parapikrasmō, kata tēn hēmeran tou peirasmou en tē erēmō</strong> — \"do not harden your hearts as you did in the rebellion, on the day of testing in the wilderness\" (<em>sklērynēte</em>: aorist subjunctive of <em>sklērunō</em>: to harden, to make stiff/callous — the aorist expresses a completed act of hardening): <em>parapikrasmos</em> (rebellion, embitterment — G3894, from <em>pikraino</em>: to make bitter; the prefix <em>para</em> adds directional force — a bitter opposition against God): the LXX translates the place-names Meribah and Massah as events (rebellion/testing) rather than preserving the Hebrew toponyms. The warning is against the internal act of hardening — a volitional stiffening against the voice.</p>",
    "9": "<p><strong>hou epeirasan hoi pateres hymōn en dokimasia kai eidon ta erga mou tessarakonta etē</strong> — \"where your ancestors tested and tried me, though they saw my works for forty years\" (<em>epeirasan</em>: tested — from <em>peirazō</em>: to test, to put to proof; <em>dokimasia</em>: testing/proving — here in apposition, intensifying): the paradox is striking: forty years of seeing the works and yet testing the worker. The sustained duration of the wilderness miracles makes the continued testing inexcusable. The \"testing\" of God is the inverse of proper faith: treating God as unproven rather than trusting the demonstrated record.</p>",
    "10": "<p><strong>dio prosōchthisa tē genea tautē kai eipon, Aei planōntai tē kardia, autoi de ouk egnōsan tas hodous mou</strong> — \"That is why I was angry with that generation; I said, Their hearts are always going astray, and they have not known my ways\" (<em>prosōchthisa</em>: I was disgusted/wearied with — from <em>prosochtizō</em>: a strong word for angry disgust, being fed up; the divine emotional response to sustained rebellion): <em>aei planōntai</em> (always they go astray — present tense: a continuous wandering): the heart-wandering is habitual, not occasional. <em>Ouk egnōsan tas hodous mou</em> (they did not know my ways): <em>egnōsan</em> — the knowing is relational/experiential (not merely intellectual) knowledge of how God works; they experienced the ways but refused to recognize them.</p>",
    "11": "<p><strong>hōs ōmosa en tē orgē mou, Ei eiseleusontai eis tēn katapausin mou</strong> — \"So I swore in my anger, They shall never enter my rest\" (Ps 95:11 LXX): <em>ōmosa en tē orgē mou</em> (I swore in my anger): the divine oath is made at the height of provocation, making it immovable. The Greek construction <em>Ei eiseleusontai</em> translates a Hebrew oath formula (ʾim + imperfect) that means \"they shall absolutely not enter\" — the \"if\" is not conditional but a strong negative assertion carried by the oath. <em>Katapausin mou</em> (my rest) — the rest is God's own rest, the eschatological Sabbath rest that the wilderness generation forfeited.</p>",
    "12": "<p><strong>blepete, adelphoi, mēpote estai en tini hymōn kardia ponēra apistias en tō apostēnai apo theou zōntos</strong> — \"See to it, brothers and sisters, that none of you has a sinful, unbelieving heart that turns away from the living God\" (<em>blepete</em>: watch/see carefully — present imperative, ongoing vigilance required): <em>kardia ponēra apistias</em> (an evil heart of unbelief — <em>ponēra</em>: wicked, harmful; <em>apistias</em>: genitive of <em>apistia</em>, unbelief): the evil heart is not characterized by gross sin but by the specific evil of <em>apistia</em> — failure to trust. <em>Apostēnai apo theou zōntos</em> (to fall away from the living God — <em>apistanai</em>: to stand away from, to defect; the word behind \"apostasy\"): the departure is directional — away from the living God. <em>Theou zōntos</em> (living God) — the life of God makes his claims binding in a way that an inert idol cannot sustain.</p>",
    "15": "<p><strong>en tō legesthai, Sēmeron ean tēs phōnēs autou akousēte, mē sklērynēte tas kardias hymōn hōs en tō parapikrasmō</strong> — \"As it has just been said: Today, if you hear his voice, do not harden your hearts as you did in the rebellion\" (Ps 95:7-8, repeated): the repetition of the Psalm citation (cf. vv7-8) within the same argument is rhetorical — the \"today\" is held open by the repeated utterance. Each reiteration of the warning extends the window of opportunity. The structure of the Greek conditional (<em>ean</em> + subjunctive) is the third-class condition: the hearing is genuinely possible but not guaranteed.</p>",
    "16": "<p><strong>tines gar akousantes parepikranan? all' ou pantes hoi exelthontes ex Aigyptou dia Mōyseōs</strong> — \"Who were they who heard and rebelled? Were they not all those Moses led out of Egypt?\" (<em>parepikranan</em>: they rebelled, made bitter — aorist indicative): the rhetorical question format drives the analysis of the wilderness failure. The answer is uncomfortable: it was not a fringe minority but the entire generation (<em>all' ou pantes</em> — \"was it not all of them?\") who had witnessed the exodus. The precedent for the warning is the majority failure of a privileged community — not outsiders who never heard.</p>",
    "17": "<p><strong>tisi de prosōchthisen tessarakonta etē; ouchi tois hamartēsasin, hōn ta kōla epesen en tē erēmō</strong> — \"And with whom was God angry for forty years? Was it not with those who sinned, whose bodies perished in the wilderness?\" (<em>ta kōla</em>: the limbs, the corpses — G2966, originally meaning \"limbs\" but used for whole corpses [LXX Num 14:29]): the duration (<em>tessarakonta etē</em>, forty years) appears again; the sustained divine displeasure was matched by the long wilderness sojourn. The physical death — bodies falling in the wilderness — is the external evidence of God's oath enacted.</p>",
    "18": "<p><strong>tisi de ōmosen mē eiseleusesthai eis tēn katapausin autou ei mē tois apeithēsasin</strong> — \"And to whom did God swear that they would never enter his rest if not to those who disobeyed?\" (<em>apeithēsasin</em>: those who disobeyed — dative plural aorist participle of <em>apeitheō</em>: to refuse to be persuaded, to disobey): Hebrews uses <em>apeitheō</em> (disobedience) as the interpretive gloss for the wilderness failure — the same root as <em>apistia</em> (unbelief, vv12,19): unbelief and disobedience are the same failure seen from different angles. One who refuses to trust God refuses to obey God.</p>",
    "19": "<p><strong>kai blepomen hoti ouk ēdynēthēsan eiselthein di' apistian</strong> — \"So we see that they were unable to enter because of their unbelief\" (<em>ouk ēdynēthēsan</em>: they were unable — not an external barrier but the incapacity produced by <em>apistia</em>): <em>di' apistian</em> (because of unbelief — the causal <em>dia</em> + accusative): unbelief is not merely a symptom but the operative cause of exclusion. The summary verse gathers the entire Ps 95 exposition: hardening → rebellion → exclusion, all rooted in the single failure of <em>apistia</em>. The connection with the following chapter is seamless: if <em>apistia</em> excluded them, only <em>pistis</em> can ensure entry.</p>"
  },
  "4": {
    "1": "<p><strong>phobēthōmen oun mēpote kataleipoménēs epangelias eiselthein eis tēn katapausin autou dokē tis ex hymōn hysterekenai</strong> — \"Let us therefore be on guard, lest any of you should seem to have fallen short of the promise of entering his rest\" (<em>phobēthōmen</em>: aorist passive subjunctive of <em>phobeomai</em>: to be afraid — the aorist hortatory subjunctive calls for a decisive posture of fear/seriousness): <em>kataleipoménēs epangelias</em> (a promise remaining, a promise still open — genitive absolute): the promise has not been voided by Israel's failure; it still stands available. <em>Dokē hysterekenai</em> (seem to have come short — <em>hystereomai</em>: to fall behind, to lack, to miss the mark): the \"seem\" is not dismissive but reflects the visible, external evidence of falling short.</p>",
    "2": "<p><strong>kai gar esmen euēngelismenoi kathaper kakeinoi, all' ouk ōphelēsen ho logos tēs akoēs ekeinous, mē synkekeramenous tē pistei tois akousasin</strong> — \"For we have had the good news proclaimed to us just as they did; but the message they heard was of no value to them, because it was not combined with faith in those who heard it\" (<em>euēngelismenoi</em>: perfect passive participle of <em>euangelizō</em>: to proclaim good news — the good news has been proclaimed and stands proclaimed over the community): <em>synkekeramenous tē pistei</em> (mixed/combined with faith — perfect passive participle of <em>synkerannymi</em>: to mix together, to blend; the hearing of the word requires faith-blending to produce nourishment): the metaphor may be dietary — food that is not digested and assimilated provides no benefit. Word without faith fails to profit.</p>",
    "3": "<p><strong>eiserchometha gar eis [tēn] katapausin hoi pisteusantes</strong> — \"Now we who have believed are entering that rest\" (<em>eiserchometha</em>: present indicative — we are entering, an ongoing process for the believing community): the present tense is significant: entering rest is not entirely future but a present experience of those who believe, alongside its future consummation. <em>Kathōs eirēken, Hōs ōmosa en tē orgē mou, Ei eiseleusontai eis tēn katapausin mou</em> (as he has said: As I swore in my anger, They shall never enter my rest): the citation of the oath is now set against the positive declaration — the excluded generation's oath-bound exclusion is the background against which the believing community's entry stands out.</p>",
    "4": "<p><strong>eirēken gar pou peri tēs hebdomēs houtōs, Kai katepausen ho theos en tē hēmera tē hebdomē apo pantōn tōn ergōn autou</strong> — \"Somewhere in Scripture God spoke about the seventh day in these words: And God rested on the seventh day from all his works\" (Gen 2:2 LXX): the indefinite <em>pou</em> (somewhere) is the same distancing device as in 2:6 — Hebrews cites the divine authority, not the human author. <em>Katepausen</em> (rested — aorist of <em>katapauō</em>: to cause to cease, to rest; the same root as <em>katapausis</em> [rest] throughout): God's own Sabbath rest is the archetype of the rest still on offer. The Gen 2:2 citation imports the cosmic Sabbath into the argument: God's rest is not a past event but an ongoing condition into which the believing may enter.</p>",
    "5": "<p><strong>kai en toutō palin, Ei eiseleusontai eis tēn katapausin mou</strong> — \"And again in this passage: They shall never enter my rest\" (Ps 95:11 repeated): the second citation of the oath, placed immediately after the Gen 2:2 citation, creates the theological juxtaposition: God's rest (Gen 2) has existed since creation; the oath (Ps 95) shows it was not entered by one generation; therefore it still awaits. The brevity of the re-citation signals that the argument has reached its pivot: the two texts together prove that the rest is real, open, and not yet universally possessed.</p>",
    "6": "<p><strong>epei oun apoleipetai tinas eiselthein eis autēn, kai hoi proteron euangelisthentes ouk eisēlthan di' apeithian</strong> — \"Therefore it still remains for some to enter that rest, and since those who formerly had the good news proclaimed to them did not enter because of disobedience\" (<em>apoleipetai</em>: remains, is left over — present passive; the rest is not exhausted but available): <em>tinas eiselthein</em> (for some to enter) — the indefinite <em>tinas</em> (some, certain ones) marks the future entry as possible but not universal. <em>Di' apeithian</em> (because of disobedience — the same root as in 3:18): disobedience is the cause of exclusion; its opposite (obedience of faith) is the condition of entry.</p>",
    "7": "<p><strong>palin tina horizei hēmeran, Sēmeron, en Dauid legōn meta tosouton chronon</strong> — \"God again set a certain day — calling it Today — saying through David much later\" (<em>horizei</em>: he sets/defines — from <em>horizō</em>: to mark off a boundary, to determine; the same root as \"horizon\"): the argument from chronology is precise: David wrote centuries after the exodus generation; the fact that God still speaks the \"today\" through David proves the rest was not definitively foreclosed in the wilderness but remained open across generations. <em>Sēmeron</em> (Today) — the temporal marker is the key: God keeps reopening the window by repeating the call, which proves the entry remains possible.</p>",
    "8": "<p><strong>ei gar autous Iēsous katepausen, ouk an peri allēs elalei meta tauta hēmeras</strong> — \"For if Joshua had given them rest, God would not have spoken later about another day\" (<em>Iēsous</em>: the Greek form of both Joshua and Jesus — a deliberate ambiguity exploited in the argument): the argument is a second-class conditional (contrary to fact): the \"if\" implies Joshua's giving of rest did not fulfill the promise. The entry into Canaan was a partial, typological rest — not the ultimate <em>katapausis</em>. The fact that God spoke the \"today\" through David after Joshua's era proves the Canaan-rest was not the final fulfillment.</p>",
    "9": "<p><strong>ara apoleipetai sabbatismos tō laō tou theou</strong> — \"There remains, then, a sabbath-rest for the people of God\" (<em>sabbatismos</em>: Sabbath-rest — G4520, a NT hapax; distinct from <em>katapausis</em> used throughout the argument): the change of noun is significant — <em>sabbatismos</em> (Sabbath-keeping, Sabbath-rest) carries the full weight of the weekly Sabbath pattern as a type of the eschatological rest. The Sabbath is not abolished but fulfilled in the rest that remains. <em>Tō laō tou theou</em> (for the people of God): the scope is corporate — the rest belongs to the covenant community, not merely individual souls.</p>",
    "10": "<p><strong>ho gar eiselthōn eis tēn katapausin autou kai autos katepausen apo tōn ergōn autou, hōsper apo tōn idiōn ho theos</strong> — \"For anyone who enters God's rest also rests from their own work, just as God rested from his\" (<em>katepausen apo tōn ergōn</em>: rested from the works — the same verb and idiom as Gen 2:2 in v4): the logic is typological: God's Sabbath rest (Gen 2) is the pattern; the believer's entry into rest follows the same pattern of ceasing from work. <em>Apo tōn idiōn</em> (from his own works): the <em>idiōn</em> specifies that the rest is from one's own efforts — faith is the opposite of self-effort as the means of entering God's presence.</p>",
    "11": "<p><strong>spoudasōmen oun eiselthein eis ekeinēn tēn katapausin, hina mē en tō autō tis hypodeigmati pesē tēs apeithias</strong> — \"Let us make every effort to enter that rest, so that no one will fall by following the same pattern of disobedience\" (<em>spoudasōmen</em>: aorist hortatory subjunctive of <em>spoudazō</em>: to hasten, to be zealous, to exert oneself — urgency): the paradox of v11 is noted: one must strive (<em>spoudasōmen</em>) to enter a rest. The effort is not the rest itself but the faith-engagement required to move toward it. <em>Hypodeigmati tēs apeithias</em> (the example/pattern of disobedience): <em>hypodeigma</em> (model, pattern, example) — the wilderness generation's failure is not merely a historical story but a structural pattern to be avoided.</p>",
    "14": "<p><strong>echontes oun archierea megan dielelythota tous ouranous, Iēsoun ton huion tou theou, kratōmen tēs homologias</strong> — \"Therefore, since we have a great high priest who has passed through the heavens, Jesus the Son of God, let us hold firmly to the faith we profess\" (<em>dielelythota tous ouranous</em>: perfect active participle of <em>dierchomai</em>: to go through — permanently in the state of having passed through the heavens): the heavenly session is not a static location but the culmination of a journey through the heavens — the Son has traversed the entire cosmic structure and now stands before the Father. <em>Megan archierea</em> (great high priest): the adjective <em>megas</em> marks the superlative quality of this priesthood over all others. <em>Kratōmen tēs homologias</em> (let us hold fast our confession — <em>krateō</em>: to hold firmly, to grip).</p>",
    "16": "<p><strong>proserchōmetha oun meta parrēsias tō thronō tēs charitos, hina labōmen eleon kai charin heurōmen eis eukairon boētheian</strong> — \"Let us then approach God's throne of grace with confidence, so that we may receive mercy and find grace to help us in our time of need\" (<em>parrēsia</em>: boldness, confidence, freedom of speech — G3954; the right to speak freely before a superior without fear): <em>tō thronō tēs charitos</em> (to the throne of grace): the heavenly throne room, which is the place of judgment in Jewish apocalyptic, is recharacterized by the high priest's presence there as a <em>charis</em>-dispensing court. <em>Eukairon boētheian</em> (timely help, well-timed help — <em>eukairos</em>: opportune, seasonable): the help is not generic but suited to the moment of need.</p>"
  },
  "5": {
    "3": "<p><strong>kai di' autēn opheilei, kathōs peri tou laou, houtōs kai peri heautou prospherein peri hamartiōn</strong> — \"This is why he has to offer sacrifices for his own sins as well as for the sins of the people\" (<em>opheilei</em>: he is obligated, he owes it — present indicative: the duty is ongoing and inherent to the Levitical priestly role): <em>peri heautou</em> (for himself) — the Levitical high priest's personal sin-offering on the Day of Atonement (Lev 16:6, 11) is the defining difference between the Aaronic and Melchizedekian priesthoods. The Son's priesthood, by contrast, does not require self-offering for personal sin (7:27 will make this explicit). The requirement functions here to establish the contrast, not to disparage the Aaronic system.</p>",
    "4": "<p><strong>kai ouch heautō tis lambanei tēn timēn, alla kaloumenos hypo tou theou, kathōsper kai Aarōn</strong> — \"And no one takes this honor on himself, but he receives it when called by God, just as Aaron was\" (<em>timēn</em>: honor — G5092; also price/value): priestly appointment is by divine call (<em>kaloumenos hypo tou theou</em> — present passive participle: one being called), not self-designation. The Aaron-precedent is the standard: the Aaronic line did not establish itself but was appointed. The negative (<em>ouch heautō</em>: not for himself) establishes the illegitimacy of self-appointment before the positive example.</p>",
    "5": "<p><strong>houtōs kai ho Christos ouch heauton edoxasen genēthēnai archierea, all' ho lalēsas pros auton, Huios mou ei sy, egō sēmeron gegennēka se</strong> — \"In the same way, Christ did not take on himself the glory of becoming a high priest. But God said to him: You are my Son; today I have become your Father\" (Ps 2:7 LXX): <em>edoxasen genēthēnai archierea</em> (glorified/honored to become high priest): the honor of the high priesthood is expressed as divine glorification. The Ps 2:7 citation establishes the Son's divine appointment as the first of two parallel appointments — sonship first, then priesthood (v6). <em>Sēmeron gegennēka se</em> (today I have begotten you): the eschatological \"today\" of the resurrection-exaltation is the moment when the divine appointment to sonship is publicly declared (cf. Acts 13:33).</p>",
    "6": "<p><strong>kathōs kai en heterō legei, Sy hiereus eis ton aiōna kata tēn taxin Melchisedek</strong> — \"And he says in another place: You are a priest forever, in the order of Melchizedek\" (Ps 110:4 LXX): <em>en heterō</em> (in another place — a second scriptural location); the two citations (Ps 2:7 + Ps 110:4) together constitute the dual divine appointment: sonship and priesthood. <em>Eis ton aiōna</em> (forever, unto the age): the eternal duration of the Melchizedekian priesthood contrasts with the Aaronic, which ended with the priest's death. <em>Kata tēn taxin Melchisedek</em> (according to the order/rank of Melchizedek — <em>taxis</em>: order, arrangement, rank): not the order as a historical institution but a pattern defined by Melchizedek's profile — priest and king without recorded genealogical succession.</p>",
    "10": "<p><strong>prosagoreuthteis hypo tou theou archiereus kata tēn taxin Melchisedek</strong> — \"and was designated by God to be high priest in the order of Melchizedek\" (<em>prosagoreuthteis</em>: aorist passive participle of <em>prosagoreuō</em>: to address by name, to designate formally — a NT hapax): the formal designation by name/title is the culmination of the preceding argument. The Melchizedek order is first invoked here, then the author declares he has more to say but must pause due to the community's spiritual immaturity (v11). The Melchizedek exposition is deferred to chapters 7-10, with this verse as the bridge.</p>",
    "12": "<p><strong>kai gar opheilontes einai didaskaloi dia ton chronon, palin chreian echete tou didaskein hymas tina ta stoicheia tēs archēs tōn logiōn tou theou, kai gegonate chreian echontes galaktos kai ou stereās trophēs</strong> — \"In fact, though by this time you ought to be teachers, you need someone to teach you the elementary truths of God's word all over again. You need milk, not solid food\" (<em>dia ton chronon</em>: because of/through the time — the time-span of their discipleship should have produced teachers; the failure is of growth, not initial hearing): <em>stoicheia tēs archēs</em> (elementary principles of the beginning — <em>stoicheia</em>: letters of the alphabet, basic elements; <em>archē</em>: beginning): the ABCs of the faith. <em>Logiōn tou theou</em> (the oracles of God — <em>logion</em>: a divine utterance, oracle): the OT scriptures as the authoritative divine speech. <em>Galaktos</em> (milk) vs. <em>stereās trophēs</em> (solid food): the dietary metaphor for theological development is Hellenistic and Jewish.</p>",
    "13": "<p><strong>pas gar ho metechōn galaktos apeiros logou dikaiosynēs, nēpios gar estin</strong> — \"Anyone who lives on milk is still an infant, unskilled in the teaching about righteousness\" (<em>apeiros</em>: inexperienced, unskilled — from <em>a</em>-privative + <em>peira</em>: experience; one who has not practiced): <em>logou dikaiosynēs</em> (the word/teaching of righteousness): the genitive is explanatory — the teaching whose content is <em>dikaiosynē</em>. In context, <em>dikaiosynē</em> likely refers to the right-standing and right-conduct that flows from mature Christological understanding, not justification in the Pauline sense. <em>Nēpios gar estin</em> (for he is an infant): <em>nēpios</em> (G3516: infant, one not yet speaking — <em>nē</em> + <em>epos</em>: non-word; one who has no mature speech).</p>",
    "14": "<p><strong>teleiōn de estin hē sterea trophē, tōn dia tēn hexin ta aisthētēria gegymnasmena echontōn pros diakrisin kalou te kai kakou</strong> — \"But solid food is for the mature, who by constant use have trained themselves to distinguish good from evil\" (<em>teleiōn</em>: of the mature/complete — G5046; the telos-root: those who have reached their purpose): <em>hexis</em> (habit, constant practice — G1838; the state resulting from repeated exercise): the <em>hexis</em> is not a natural aptitude but an acquired state from repeated practice (<em>dia tēn hexin</em>). <em>Aisthētēria</em> (perceptual organs of moral discernment — G145; a philosophical term for the sensory-like faculties of moral perception): the <em>aisthētēria</em> are trained (<em>gegymnasmena</em>: perfect passive — permanently exercised, as an athlete trains) toward <em>diakrisin kalou te kai kakou</em> (discernment of good and evil). The mature discernment of the Melchizedek material requires exactly this kind of trained moral-theological perception.</p>"
  }
}
''')

def main():
    existing = load_comm('mkt-original', 'hebrews')
    merge_comm(existing, HEBREWS)
    save_comm('mkt-original', 'hebrews', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Hebrews mkt-original gaps filled: {len(existing)} chapters, {total} verses written.')

if __name__ == '__main__':
    main()
